class Solution:
    def maxLength(self, arr):
        """
        :type arr: List[str]
        :rtype: int
        """
        # Filter strings with duplicate chars
        valid = []
        for s in arr:
            if len(s) == len(set(s)):
                valid.append(set(s))

        def dfs(index, current_chars):
            max_len = len(current_chars)

            for i in range(index, len(valid)):
                # If no overlap, combine
                if not (valid[i] & current_chars):
                    max_len = max(max_len, dfs(i + 1, current_chars | valid[i]))

            return max_len

        return dfs(0, set())
